import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
import Layout_v2 from "@components/layout_v2";
import Seo from "@components/seo";
import { useLocation } from "@reach/router";
import HireDeveloper from "@screens/hiringPages/hire-developers";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";
import icon_1 from "@images/hirescreens/devPages/icons/icon_1.svg";
import icon_2 from "@images/hirescreens/devPages/icons/icon_2.svg";
import icon_3 from "@images/hirescreens/devPages/icons/icon_3.svg";
import icon_4 from "@images/hirescreens/devPages/icons/icon_4.svg";

import bank from "@images/hirescreens/devPages/icons/bank.svg";
import technology from "@images/hirescreens/devPages/icons/technology.svg";
import web3 from "@images/hirescreens/devPages/icons/web3.svg";
import sports from "@images/hirescreens/devPages/icons/sports.svg";
import insurance from "@images/hirescreens/devPages/icons/insurance.svg";
import education from "@images/hirescreens/devPages/icons/education.svg";
import real_estate from "@images/hirescreens/devPages/icons/real_estate.svg";
import healthcare from "@images/hirescreens/devPages/icons/healthcare.svg";
import supply_chain from "@images/hirescreens/devPages/icons/supply_chain.svg";
import blockchain from "@images/hirescreens/devPages/icons/blockchain.svg";
import game from "@images/hirescreens/devPages/icons/game.svg";
import cybersecurity from "@images/hirescreens/devPages/icons/cybersecurity.svg";

import react from "@styles/assets/images/private-blockchain/devicons/react.svg";
import nodejs from "@styles/assets/images/private-blockchain/devicons/nodejs.svg";
import devicon_flutter from "@styles/assets/images/private-blockchain/devicons/devicon_flutter.svg";
import kotlin from "@styles/assets/images/Techstack/kotlin.svg";
import python from "@styles/assets/images/private-blockchain/devicons/python.svg";
import nextjs from "@styles/assets/images/hero_v2/tech-icons/nextjs.svg";
import aws from "@styles/assets/images/Techstack/aws.svg";

import icon1 from "@images/hirescreens/devPages/icons/chooseIcons/idea_card.svg";
import icon2 from "@images/hirescreens/devPages/icons/chooseIcons/secure.svg";
import icon3 from "@images/hirescreens/devPages/icons/chooseIcons/cycle_Icon.svg";
import icon4 from "@images/hirescreens/devPages/icons/chooseIcons/database_setting.svg";
import icon5 from "@images/hirescreens/devPages/icons/chooseIcons/code_waves.svg";
import icon6 from "@images/hirescreens/devPages/icons/chooseIcons/communication.svg";
const HireRemoteDevelopers = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Hire Remote Developer", link: null },
  ];
  const { data } = props;
  const location = useLocation();
  const fileUrl =
    data?.HireRemoteDevelopersImg?.childImageSharp?.gatsbyImageData?.images
      ?.fallback?.src;
  const validData = data?.allMetaJson?.nodes[0];

  const pageData = {
    home: {
      tag: "Hire Our Remote Development Team",
      review: 4,
      title: "Hire a Remote Development Team for Your Vision",
      description:
        "We provide skilled remote development teams that deliver scalable, high-quality solutions and bring your product vision to life.",
      image: data?.heroImage,
      imageAlt: "Hire Remote Development Team",
    },

    achieves: {
      boxData: [
        {
          id: 1,
          number: 120,
          isPercentage: false,
          title: "Projects Delivered",
        },
        {
          id: 2,
          number: 5,
          isPercentage: false,
          title: "Teams Available",
        },
        {
          id: 3,
          number: 15,
          isPercentage: false,
          title: "Industries Served",
        },
        {
          id: 4,
          number: 98,
          isPercentage: true,
          title: "Client Retention Rate",
        },
      ],
    },

    about: {
      badgeText: "About",
      title: "Remote Development. Unlimited Possibilities",
      description:
        "Our remote development teams combine strong engineering, clean architecture, and adaptive workflows to build powerful, future-ready digital products. Whether it’s front-end, back-end, full-stack development, cloud integration, or complete product engineering, we deliver high-performing solutions tailored to your business needs.",
      boxData: [
        { id: 1, title: "End-to-End Remote Team Capability" },
        { id: 2, title: "High Productivity Across Time Zones" },
        { id: 3, title: "Flexible Skill Sets for Any Tech Stack" },
        { id: 4, title: "Robust Workflow & Quality Standards" },
        { id: 5, title: "Seamless Collaboration With In-House Team" },
        { id: 6, title: "Transparent Communication & Updates" },
      ],
    },

    ourService: {
      badgeText: "Our Services",
      title: "End-to-End Remote Development Services",
      description:
        "Our remote development teams integrate seamlessly into your workflow, providing the expertise you need to accelerate product development. From frontend and backend engineering to QA, DevOps, and cloud support, we offer dedicated talent that works as an extension of your in-house team. Scale faster, reduce overhead, and build high-quality products with reliable remote engineers you can trust.",
      boxData: [
        {
          id: 1,
          title: "Build High-Quality Digital Products",
          desc: "We assemble remote development teams that deliver fast, reliable, and scalable digital solutions tailored to your business needs.",
        },
        {
          id: 2,
          title: "Develop Robust & Efficient Software Systems",
          desc: "Our engineers build clean, secure, and optimized codebases designed to handle complex workflows and high-performance requirements.",
        },
        {
          id: 3,
          title: "Create Seamless User Experiences",
          desc: "From UI to backend logic, our teams craft smooth, intuitive experiences that improve usability and elevate product value.",
        },
        {
          id: 4,
          title: "Integrate APIs, Tools & Third-Party Platforms",
          desc: "We ensure hassle-free integration with APIs, services, databases, and tools—making your product connected, stable, and future-ready.",
        },
      ],
    },

    ourTechs: {
      badgeText: "Our Technology Stack",
      title: "Our Tech Stack",
      description:
        "Our tech stack for Remote Development Teams includes modern frameworks, cloud platforms, collaboration tools, and secure development practices.",
      boxData: [
        { id: 1, title: "React", icon: react },
        { id: 2, title: "Next.js", icon: nextjs },
        { id: 3, title: "Node JS", icon: nodejs },
        { id: 4, title: "Python", icon: python },
        { id: 5, title: "Flutter", icon: devicon_flutter },
        { id: 6, title: "Kotlin", icon: kotlin },
        { id: 7, title: "AWS", icon: aws },
      ],
    },

    whyChooseUs: {
      badgeText: "Why choose us?",
      title: "What Makes Us Different",
      description:
        "We provide skilled, scalable, and fully-managed remote development teams with seamless communication and efficient project delivery.",
      boxData: [
        {
          id: 1,
          title: "Expert Remote Developers",
          icon: icon1,
          desc: "Our remote team brings deep experience in web, mobile, and cloud solutions, ensuring high-quality development across time zones and platforms.",
        },
        {
          id: 2,
          title: "Security & Compliance Focus",
          icon: icon2,
          desc: "We follow strict security protocols, code audits, and best practices to safeguard your data, systems, and users.",
        },
        {
          id: 3,
          title: "End-to-End Project Delivery",
          icon: icon3,
          desc: "From requirement analysis to deployment and maintenance, our remote team manages the full development lifecycle efficiently.",
        },
        {
          id: 4,
          title: "Scalable & High-Performance Solutions",
          icon: icon4,
          desc: "We design systems that handle growth, high traffic, and complex workloads while maintaining performance and reliability.",
        },
        {
          id: 5,
          title: "Flexible Technology Expertise",
          icon: icon5,
          desc: "Our team works across multiple stacks and platforms—web, mobile, cloud, and enterprise systems—tailored to your project needs.",
        },
        {
          id: 6,
          title: "Transparent & On-Time Delivery",
          icon: icon6,
          desc: "With structured workflows, clear reporting, and consistent updates, we ensure smooth collaboration and on-time project delivery.",
        },
      ],
    },

    devProcess: {
      badgeText: "Our Development Process",
      title: "How We Shape Your Remote Product",
      boxData: [
        { id: 1, icon: icon_1, title: "Share Your Requirements" },
        { id: 2, icon: icon_2, title: "Consultation & Planning" },
        { id: 3, icon: icon_3, title: "Proposal & Agreement" },
        { id: 4, icon: icon_4, title: "Start Collaboration" },
      ],
    },

    ourExperts: {
      badgeText: "Our Expertise",
      title: "Industries We Serve",
      boxData: [
        { id: 1, icon: bank, title: "Financial Services" },
        { id: 2, icon: technology, title: "SaaS & Technology" },
        { id: 3, icon: web3, title: "Web3" },
        { id: 4, icon: sports, title: "E-Commerce & Retail" },
        { id: 5, icon: insurance, title: "Insurance" },
        { id: 6, icon: education, title: "Education" },
        { id: 7, icon: real_estate, title: "Real Estate" },
        { id: 8, icon: healthcare, title: "Healthcare" },
        { id: 9, icon: supply_chain, title: "Supply Chain" },
        { id: 10, icon: blockchain, title: "Blockchain" },
        { id: 11, icon: game, title: "Gaming, Metaverse" },
        { id: 12, icon: cybersecurity, title: "Cybersecurity" },
      ],
    },

    reviews: {
      title: "Client Reviews",
      description:
        "Our clients trust us for delivering secure, scalable blockchain solutions with exceptional quality and consistent communication.",
      boxData: [
        {
          id: 1,
          rating: 4,
          name: "Monisha Ravi",
          review:
            "The remote team quickly adapted to our workflow and delivered high-quality features on time. Collaboration was seamless across different time zones.",
        },
        {
          id: 2,
          rating: 4,
          name: "Vishwa Jayaraj",
          review:
            "They handled complex modules with precision and maintained excellent communication throughout the project. Truly reliable remote developers.",
        },
        {
          id: 3,
          rating: 4,
          name: "Yazhika Manickam",
          review:
            "Flexible, responsive, and skilled. They exceeded our expectations and integrated smoothly with our in-house processes.",
        },
      ],
    },

    faq: [
      {
        question: "How does a remote development team work?",
        answer:
          "A remote team collaborates via digital tools like Slack, Zoom, and project management platforms to deliver development projects from anywhere in the world.",
      },
      {
        question: "How do you ensure communication with a remote team?",
        answer:
          "Regular meetings, progress tracking, and clear reporting tools ensure smooth communication and alignment with project goals.",
      },
      {
        question: "Can a remote team handle full-stack projects?",
        answer:
          "Yes. A remote team can handle front-end, back-end, testing, and deployment depending on their expertise.",
      },
      {
        question: "How do I manage time zone differences?",
        answer:
          "Remote teams often adopt overlapping working hours, asynchronous updates, and clear milestone planning to stay coordinated.",
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <main>
        <HireDeveloper db={db} data={pageData} />
      </main>
    </Layout_v2>
  );
};

export default HireRemoteDevelopers;
export const queryData = graphql`
  query HireRemoteDevelopersPageQuery {
    HireRemoteDevelopersImg: file(
      relativePath: { eq: "hire-remote-developers.png" }
    ) {
      childImageSharp {
        gatsbyImageData
      }
    }
    heroImage: file(
      relativePath: { eq: "hirescreens/devPages/remote-developers-hero.webp" }
    ) {
      childImageSharp {
        gatsbyImageData(
          layout: CONSTRAINED
          width: 1200
          quality: 90
          placeholder: BLURRED
        )
      }
    }

    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }

    allMetaJson(filter: { slug: { eq: "hire-remote-developers" } }) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
